enum DisconnectReason { userEnded, remoteEnded, networkError, timeout, byeReceived, maxDuration, permissionRevoked, unknown } extension DisconnectReasonExt on DisconnectReason { String get message { switch(this) { case DisconnectReason.userEnded: return 'You ended the session'; case DisconnectReason.remoteEnded: return 'Remote device ended session'; case DisconnectReason.networkError: return 'Network connection lost'; case DisconnectReason.timeout: return 'Connection timed out'; default: return 'Session ended'; } } }